  const versionOffset = (version - 1) * 25;

  return [
    {
      id: 1,
      sku: 'LAP-001',
      name: 'Laptop Pro 15',
      price: 999 + versionOffset,
      inventory: Math.max(4, 18 - version),
      availability: version % 2 === 0 ? 'Backorder' : 'In stock',
    },
    {
      id: 2,
      sku: 'PHN-002',
      name: 'Phone Max',
      price: 699 + versionOffset,
      inventory: 32 + version,
      availability: 'In stock',
    },
    {
      id: 3,
      sku: 'TAB-003',
      name: 'Tablet Air',
      price: 499 + versionOffset,
      inventory: Math.max(0, 12 - version),
      availability: version % 3 === 0 ? 'Low stock' : 'In stock',
    },
    {
      id: 4,
      sku: 'HDP-004',
      name: 'Noise Canceling Headphones',
      price: 199 + versionOffset,
      inventory: 45 + version * 2,
      availability: 'In stock',
    },
    {
      id: 5,
      sku: 'WTC-005',
      name: 'Smart Watch',
      price: 299 + versionOffset,
      inventory: Math.max(0, 10 - version),
      availability: version >= 4 ? 'Limited availability' : 'In stock',
    },
  ];
}

export async function getAllProducts() {
  'use cache';
  cacheTag('products');

  // Simulate a read-heavy catalog query.
  await new Promise((resolve) => setTimeout(resolve, 100));

  return {
    version: catalogVersion,
    syncedAt: new Date(Date.UTC(2026, 6, 17, 8, catalogVersion * 3, 0)).toISOString(),
    products: buildCatalog(catalogVersion),
  };
}

export async function syncLatestCatalog() {
  // Simulate a long-running ERP/PIM sync that completes in the background.
  await new Promise((resolve) => setTimeout(resolve, 1500));
  catalogVersion += 1;

  return {
    version: catalogVersion,
    syncedAt: new Date(Date.UTC(2026, 6, 17, 8, catalogVersion * 3, 0)).toISOString(),
  };
}

import { revalidateTag } from 'next/cache';
import { getAllProducts, syncLatestCatalog } from '@/lib/db';

function formatCurrency(value: number) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(value);
}

function formatSyncTime(value: string) {
  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
    timeZone: 'UTC',
  }).format(new Date(value));
}

export default async function Page() {
  async function syncCatalogAction() {
    'use server';

    void syncLatestCatalog().then(() => {
      revalidateTag('products', 'max');
    });
  }

  const catalog = await getAllProducts();

  return (
    <main style={{ padding: '32px', fontFamily: 'Arial, sans-serif' }}>
      <section
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          gap: '24px',
          marginBottom: '24px',
        }}
      >
        <div>
          <p style={{ margin: 0, color: '#666', fontSize: '14px', fontWeight: 700 }}>
            Admin catalog
          </p>
          <h1 style={{ margin: '8px 0 12px', fontSize: '32px' }}>Product catalog</h1>
          <p style={{ margin: 0, maxWidth: '720px', color: '#444', lineHeight: 1.5 }}>
            Catalog reads are cached with the <code>products</code> tag so admins can browse quickly.
            Sync requests refresh the catalog in the background and make updated pricing,
            inventory, and availability visible shortly after across catalog views.
          </p>
        </div>

        <form action={syncCatalogAction}>
          <button
            type="submit"
            style={{
              border: 0,
              borderRadius: '10px',
              background: '#111827',
              color: '#fff',
              padding: '12px 18px',
              fontSize: '14px',
              fontWeight: 700,
              cursor: 'pointer',
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </section>

      <section
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(3, minmax(0, 1fr))',
          gap: '16px',
          marginBottom: '24px',
        }}
      >
        <div style={{ padding: '16px', border: '1px solid #e5e7eb', borderRadius: '12px' }}>
          <div style={{ color: '#666', fontSize: '13px' }}>Catalog version</div>
          <div style={{ marginTop: '8px', fontSize: '24px', fontWeight: 700 }}>{catalog.version}</div>
        </div>
        <div style={{ padding: '16px', border: '1px solid #e5e7eb', borderRadius: '12px' }}>
          <div style={{ color: '#666', fontSize: '13px' }}>Last sync snapshot</div>
          <div style={{ marginTop: '8px', fontSize: '24px', fontWeight: 700 }}>
            {formatSyncTime(catalog.syncedAt)}
          </div>
        </div>
        <div style={{ padding: '16px', border: '1px solid #e5e7eb', borderRadius: '12px' }}>
          <div style={{ color: '#666', fontSize: '13px' }}>Consistency mode</div>
          <div style={{ marginTop: '8px', fontSize: '24px', fontWeight: 700 }}>Stale-while-revalidate</div>
        </div>
      </section>

      <div
        style={{
          overflow: 'hidden',
          border: '1px solid #e5e7eb',
          borderRadius: '12px',
          background: '#fff',
        }}
      >
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f9fafb' }}>
            <tr>
              <th style={{ textAlign: 'left', padding: '14px 16px', fontSize: '13px' }}>SKU</th>
              <th style={{ textAlign: 'left', padding: '14px 16px', fontSize: '13px' }}>Product</th>
              <th style={{ textAlign: 'left', padding: '14px 16px', fontSize: '13px' }}>Price</th>
              <th style={{ textAlign: 'left', padding: '14px 16px', fontSize: '13px' }}>Inventory</th>
              <th style={{ textAlign: 'left', padding: '14px 16px', fontSize: '13px' }}>Availability</th>
            </tr>
          </thead>
          <tbody>
            {catalog.products.map((product) => (
              <tr key={product.id} style={{ borderTop: '1px solid #e5e7eb' }}>
                <td style={{ padding: '14px 16px', fontFamily: 'monospace' }}>{product.sku}</td>
                <td style={{ padding: '14px 16px', fontWeight: 600 }}>{product.name}</td>
                <td style={{ padding: '14px 16px' }}>{formatCurrency(product.price)}</td>
                <td style={{ padding: '14px 16px' }}>{product.inventory}</td>
                <td style={{ padding: '14px 16px' }}>{product.availability}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}
